using FluentValidation;using Microsoft.Extensions.Logging;namespace Smoower.Minified.SampleApi;[API,RT("api/users")]public class UsersController(AppDb db,IValidator<UserIn> val,ILogger<UsersController> log,Clock clock):Ctl{[HG("{id}")][P200,P404]public Tr Get(int id)=>db.Users.nt().w(x=>x.Id==id).s(x=>new{x.Id,x.Name,x.Email}).ok1();[HG]public Tr All()=>db.Users.nt().s(x=>new{x.Id,x.Name,x.Email}).okl();[HPO][P201,P400]public async Tr Post(UserIn r){var v=await val.ValidateAsync(r);if(!v.IsValid)return BadRequest(v.Errors);var x=await db.add(new User{Name=r.Name,Email=r.Email});log.inf("created user {Id} at {At:o}",x.Id,clock.UtcNow);return new{x.Id,x.Name,x.Email}.created();}[HD("{id}")][P204,P404]public Tr Del(int id)=>db.delById<User>(id);}public record UserIn(string Name,string Email);